public class Solution {
    private static int maxLen = 0;

    public static long solve(long n, long[][] edges, String label) {
        maxLen = 0;
        int numNodes = (int) n;
        List<List<Integer>> graph = new ArrayList<>();
        for (int i = 0; i < numNodes; i++) {
